import { Inter } from 'next/font/google';
import { ModernNavbar } from '@/components/ModernNavbar';
import { Footer } from '@/components/Footer';
import { LanguageProvider } from '@/lib/i18n/context';
import { supportedLanguages, languages, SupportedLanguage } from '@/lib/i18n/config';
import { notFound } from 'next/navigation';

const inter = Inter({ subsets: ['latin'] });

interface LangLayoutProps {
  children: React.ReactNode;
  params: { lang: string };
}

export async function generateStaticParams() {
  return supportedLanguages.map((lang) => ({ lang }));
}

export default function LangLayout({ children, params }: LangLayoutProps) {
  const lang = params.lang as SupportedLanguage;
  
  if (!supportedLanguages.includes(lang)) {
    notFound();
  }

  const currentLang = languages[lang];

  return (
    <html lang={lang} dir={currentLang.dir} suppressHydrationWarning>
      <body className={currentLang.dir === 'ltr' ? inter.className : undefined}>
        <LanguageProvider initialLanguage={lang}>
          <div className="min-h-screen flex flex-col">
            <ModernNavbar />
            <main id="main-content" className="flex-1">
              {children}
            </main>
            <Footer />
          </div>
        </LanguageProvider>
      </body>
    </html>
  );
}